props.extensibilityCode:
// NavigationMenu controlado com delays customizados
<NavigationMenu
  value={active}
  onValueChange={setActive}
  delayDuration={150}
  skipDelayDuration={250}
  aria-label="Navegação principal"
>
  <NavigationMenuList>...</NavigationMenuList>
  <NavigationMenuViewport />
</NavigationMenu>

tokens.customizationCode:
/* Override de cor da barra para tema com header colorido */
[data-slot='navigation-menu'] {
  background-color: hsl(var(--card));
}

/* Trigger ativo com sublinhado em vez de bg */
[data-slot='navigation-menu-trigger'][data-state='open'] {
  background-color: transparent;
  border-bottom: 2px solid hsl(var(--primary));
}

